// spec-based — <hazard_pointer> not yet implemented by any compiler
#include <hazard_pointer>
#include <atomic>
#include <print>

struct Node : std::hazard_pointer_obj_base<Node> {
    int value;
};

std::atomic<Node*> global_node{nullptr};

void reader_thread() {
    auto hp = std::make_hazard_pointer(std::hazard_pointer_default_domain());
    Node* p;
    do {
        p = hp.protect(global_node);
    } while (p != global_node.load(std::memory_order_acquire));

    if (p) {
        std::println("value: {}", p->value); // safe to dereference
    }
    hp.reset_protection(); // done with p
}

// spec-based — <hazard_pointer> not yet implemented by any compiler
#include <hazard_pointer>
#include <atomic>
#include <print>

struct Node : std::hazard_pointer_obj_base<Node> {
    int value;
    Node(int v) : value(v) {}
};

std::atomic<Node*> current{new Node(1)};

void writer_update(int new_val) {
    Node* old_node = current.exchange(new Node(new_val),
                                      std::memory_order_acq_rel);
    // old_node is no longer reachable from current,
    // but readers may still hold it via hazard pointers
    old_node->retire(); // actual delete deferred until no HP references it
}

void reader_snapshot() {
    auto hp = std::make_hazard_pointer(std::hazard_pointer_default_domain());
    Node* p;
    do {
        p = hp.protect(current);
    } while (p != current.load(std::memory_order_acquire));

    std::println("read value: {}", p->value);
    hp.reset_protection();
}

