// spec-based — <rcu> not yet implemented by any compiler
#include <rcu>
#include <atomic>
#include <string>
#include <print>

struct Config : std::rcu_obj_base<Config> {
    std::string endpoint;
    int timeout_ms;
};

std::atomic<Config*> current_config{new Config{"localhost", 5000}};

void handle_request() {
    std::rcu_reader reader; // enter read-side critical section
    Config* cfg = current_config.load(std::memory_order_acquire);
    // cfg is guaranteed valid for the lifetime of reader
    std::println("connecting to {} with {}ms timeout",
                 cfg->endpoint, cfg->timeout_ms);
    // reader destructor: exit critical section
}

// spec-based — <rcu> not yet implemented by any compiler
#include <rcu>
#include <atomic>
#include <string>

struct Config : std::rcu_obj_base<Config> {
    std::string endpoint;
    int timeout_ms;
};

std::atomic<Config*> current_config{new Config{"localhost", 5000}};

void update_config(std::string new_endpoint, int new_timeout) {
    Config* old = current_config.load(std::memory_order_acquire);
    Config* updated = new Config{new_endpoint, new_timeout}; // copy + modify

    // atomically publish new version
    current_config.store(updated, std::memory_order_release);

    // schedule old config for deletion after next grace period
    // (old may still be in use by existing readers)
    old->retire();
    // retire() is non-blocking — writer returns immediately
    // the runtime will call delete old after the grace period ends
}

