int main() {
    std::atomic<bool> ready{false};
    int data = 0;

    // Simulate producer side
    data = 99;
    ready.store(true, std::memory_order_release);

    // Simulate consumer side (same thread — but same memory_order semantics apply)
    bool seen = ready.load(std::memory_order_acquire);
    std::println("ready={} data={}", seen, data);
}

#include <atomic>
#include <print>

int main() {
    std::atomic<int> x{0}, y{0};

    // relaxed stores + release fence
    x.store(1, std::memory_order_relaxed);
    y.store(2, std::memory_order_relaxed);
    std::atomic_thread_fence(std::memory_order_release);

    // acquire fence + relaxed loads
    std::atomic_thread_fence(std::memory_order_acquire);
    int vx = x.load(std::memory_order_relaxed);
    int vy = y.load(std::memory_order_relaxed);
    std::println("x={} y={}", vx, vy);
}

